import{_ as a,o as t,c as i,ae as s}from"./chunks/framework.BMBGeRFM.js";const u=JSON.parse('{"title":"Thuli, the official Farben REPL","description":"","frontmatter":{"title":"Thuli, the official Farben REPL","date":"2026-04-19T00:00:00.000Z"},"headers":[],"relativePath":"news/2026-04-19-thuli-repl.md","filePath":"news/2026-04-19-thuli-repl.md"}'),l={name:"news/2026-04-19-thuli-repl.md"};function n(o,e,r,h,p,d){return t(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="thuli-the-official-farben-repl" tabindex="-1">Thuli, the official Farben REPL <a class="header-anchor" href="#thuli-the-official-farben-repl" aria-label="Permalink to &quot;Thuli, the official Farben REPL&quot;">​</a></h1><p>Farben now has an interactive REPL! Introducing Thuli, the interactive REPL I&#39;ve been building, is now ready for use. It provides a quiet, focused space to type Farben markup and see the rendered output in real time.</p><h2 id="what-it-does" tabindex="-1">What it does <a class="header-anchor" href="#what-it-does" aria-label="Permalink to &quot;What it does&quot;">​</a></h2><p>Thuli is a small interactive shell, similar to <code>python</code> or <code>irb</code>, but for Farben markup. You can:</p><ul><li>Type markup and see the rendered terminal output instantly</li><li>Define custom styles on the fly with <code>/style</code></li><li>Inspect what the parser produces with <code>/show</code></li><li>Load themes from <code>.frb.toml</code> files</li><li>Use one-shot mode from the command line</li></ul><h2 id="install" tabindex="-1">Install <a class="header-anchor" href="#install" aria-label="Permalink to &quot;Install&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cargo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> thuli</span></span></code></pre></div><p>Or fetch from <a href="https://codeberg.org/razkar/thuli" target="_blank" rel="noreferrer">Codeberg</a>.</p><h2 id="commands" tabindex="-1">Commands <a class="header-anchor" href="#commands" aria-label="Permalink to &quot;Commands&quot;">​</a></h2><ul><li><code>/help</code> — show all commands</li><li><code>/quit</code> — exit the REPL</li><li><code>/tags</code> — list all available tags</li><li><code>/style &lt;name&gt; &lt;markup&gt;</code> — register a new style</li><li><code>/show &lt;markup&gt;</code> — render and show token/ansi output</li><li><code>/theme</code> — show theme config status</li><li><code>/load &lt;path&gt;</code> — load styles from a file</li></ul><h2 id="why-thuli" tabindex="-1">Why Thuli? <a class="header-anchor" href="#why-thuli" aria-label="Permalink to &quot;Why Thuli?&quot;">​</a></h2><p>The name comes from Zulu, meaning &quot;quiet&quot; or &quot;peace&quot;. A calm space for experimenting with markup, without noise.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ thuli</span></span>
<span class="line"><span>thuli 1.0.0  ·  the official farben repl, previewing frbVER</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&gt;&gt;&gt; [bold red]Error:[/] something broke</span></span>
<span class="line"><span>    Error: something broke</span></span>
<span class="line"><span>&gt;&gt;&gt; /quit</span></span>
<span class="line"><span>make great things with farben &lt;3</span></span>
<span class="line"><span></span></span>
<span class="line"><span>$</span></span></code></pre></div><p>Read more in the <a href="https://codeberg.org/razkar/thuli" target="_blank" rel="noreferrer">Thuli README</a>.</p><p>Thuli is truly one of the most fun projects to make yet, and it couldn&#39;t be possible without Farben itself. Thank you all for supporting Farben!</p><p>Make great things with Farben.</p><p>Cheers, RazkarStudio.</p>`,17)])])}const m=a(l,[["render",n]]);export{u as __pageData,m as default};
